function calculateTotalPrice(cart: Cart): number | Error {
    if (cart.items.length === 0) {
        return new Error("Le panier est vide.");
    }

    if (cart.tax < 0) {
        return new Error("La taxe ne peut pas être négative.");
    }

    const totalPrice = cart.items.reduce((accumulator, item) => {
        if (item.price === undefined || item.price === null) {
            return new Error("Un item n'a pas de prix défini.");
